import React, { useEffect, useState } from "react";
import API from "../../api/api";

const RateFreelancer = () => {
  const [projects, setProjects]     = useState([]);
  const [loading, setLoading]       = useState(true);
  const [modal, setModal]           = useState(null);
  const [rating, setRating]         = useState(5);
  const [review, setReview]         = useState("");
  const [hover, setHover]           = useState(0);
  const [submitting, setSubmitting] = useState(false);
  const [reviewed, setReviewed]     = useState({});
  const [success, setSuccess]       = useState("");

  useEffect(() => {
    const load = async () => {
      try {
        const projRes = await API.get("/projects/client");
        const allProjects = projRes.data || [];

        // Fetch proposals for each project
        const withProposals = await Promise.all(
          allProjects.map(async (p) => {
            try {
              const propRes = await API.get(`/proposals/project/${p.id}`);
              const accepted = (propRes.data || []).find(pr => pr.status === "accepted");
              return { ...p, acceptedProposal: accepted || null };
            } catch {
              return { ...p, acceptedProposal: null };
            }
          })
        );
        // Only show projects with accepted proposals
        setProjects(withProposals.filter(p => p.acceptedProposal));
      } catch (err) { console.error(err); }
      setLoading(false);
    };
    load();
  }, []);

  const openModal = (project) => {
    setModal({
      project,
      freelancer_id:   project.acceptedProposal.freelancer_id,
      freelancer_name: project.acceptedProposal.freelancer_name,
    });
    setRating(5);
    setReview("");
    setHover(0);
  };

  const submitReview = async () => {
    setSubmitting(true);
    try {
      await API.post("/reviews", {
        project_id:   modal.project.id,
        freelancer_id: modal.freelancer_id,
        rating,
        review,
      });
      setReviewed(prev => ({ ...prev, [modal.project.id]: { rating, review } }));
      setSuccess(`Review submitted for ${modal.freelancer_name}!`);
      setModal(null);
      setTimeout(() => setSuccess(""), 3000);
    } catch (err) {
      alert(err.response?.data?.message || "Error submitting review");
    }
    setSubmitting(false);
  };

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-3xl mx-auto">

        <h1 className="text-2xl font-bold text-gray-800 mb-1">Rate Freelancers</h1>
        <p className="text-gray-500 text-sm mb-6">Review freelancers for your accepted projects</p>

        {success && (
          <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-lg mb-5 text-sm">
            ⭐ {success}
          </div>
        )}

        {projects.length === 0 ? (
          <div className="bg-white rounded-xl p-12 text-center shadow-sm border border-gray-100">
            <div className="text-5xl mb-3">⭐</div>
            <p className="text-gray-500 mb-1">No accepted projects to review yet.</p>
            <p className="text-gray-400 text-sm">Once you accept a freelancer's proposal, you can rate them here.</p>
          </div>
        ) : (
          <div className="space-y-4">
            {projects.map((p) => {
              const alreadyReviewed = reviewed[p.id];
              return (
                <div key={p.id} className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">
                  <div className="flex justify-between items-start">
                    <div className="flex-1 min-w-0">
                      <h3 className="font-bold text-gray-800 text-lg">{p.title}</h3>
                      <div className="flex items-center gap-2 mt-1">
                        <div className="w-7 h-7 bg-teal-600 text-white rounded-full flex items-center justify-center text-xs font-bold">
                          {p.acceptedProposal.freelancer_name?.charAt(0)?.toUpperCase()}
                        </div>
                        <span className="text-sm text-gray-600 font-medium">{p.acceptedProposal.freelancer_name}</span>
                        <span className="text-teal-600 text-sm font-bold">· ₹{p.acceptedProposal.bid}</span>
                      </div>
                    </div>

                    <div className="ml-4">
                      {alreadyReviewed ? (
                        <div className="text-right">
                          <p className="text-yellow-500 text-lg">{"⭐".repeat(alreadyReviewed.rating)}</p>
                          <p className="text-xs text-gray-400">Reviewed</p>
                        </div>
                      ) : (
                        <button onClick={() => openModal(p)}
                          className="bg-yellow-400 hover:bg-yellow-500 text-white px-4 py-2 rounded-lg text-sm font-medium transition">
                          ⭐ Rate Now
                        </button>
                      )}
                    </div>
                  </div>

                  {alreadyReviewed && alreadyReviewed.review && (
                    <div className="mt-3 bg-yellow-50 border border-yellow-200 rounded-lg p-3">
                      <p className="text-yellow-700 text-sm">"{alreadyReviewed.review}"</p>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* ===== RATING MODAL ===== */}
      {modal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 px-4">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-md p-6">
            <div className="flex justify-between items-start mb-5">
              <div>
                <h2 className="text-lg font-bold text-gray-800">Rate Freelancer</h2>
                <p className="text-sm text-gray-500">{modal.freelancer_name} · {modal.project.title}</p>
              </div>
              <button onClick={() => setModal(null)}
                className="text-gray-400 hover:text-gray-600 text-xl font-bold">✕</button>
            </div>

            {/* STAR RATING */}
            <div className="mb-5">
              <label className="block text-sm font-medium text-gray-700 mb-3">Rating</label>
              <div className="flex gap-2">
                {[1,2,3,4,5].map((star) => (
                  <button key={star}
                    onMouseEnter={() => setHover(star)}
                    onMouseLeave={() => setHover(0)}
                    onClick={() => setRating(star)}
                    className="text-3xl transition-transform hover:scale-110">
                    {star <= (hover || rating) ? "⭐" : "☆"}
                  </button>
                ))}
              </div>
              <p className="text-sm text-gray-500 mt-2">
                {rating === 1 ? "Poor" : rating === 2 ? "Fair" : rating === 3 ? "Good" : rating === 4 ? "Very Good" : "Excellent"}
              </p>
            </div>

            {/* REVIEW TEXT */}
            <div className="mb-6">
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Review <span className="text-gray-400">(optional)</span>
              </label>
              <textarea value={review} onChange={e => setReview(e.target.value)}
                rows={3} placeholder="Share your experience working with this freelancer..."
                className="w-full border border-gray-300 px-3 py-2 rounded-lg text-sm focus:ring-2 focus:ring-teal-500 outline-none resize-none" />
            </div>

            <div className="flex gap-3">
              <button onClick={submitReview} disabled={submitting}
                className="flex-1 bg-yellow-400 hover:bg-yellow-500 text-white py-2 rounded-lg text-sm font-semibold transition disabled:opacity-50">
                {submitting ? "Submitting..." : "⭐ Submit Review"}
              </button>
              <button onClick={() => setModal(null)}
                className="px-5 py-2 rounded-lg text-sm font-medium border border-gray-300 text-gray-600 hover:bg-gray-50 transition">
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default RateFreelancer;
